// ============================================================
// PROCESAR EXCEL ROBUSTO v2 - Sin GPT-4o
// Soporta multi-sheet, horarios multi-linea, formatos variados
// ============================================================

const items = $input.all();
const carreraData = $('Verificar Carrera en BD').first().json;
const validarData = $('Validar Carrera').first().json;
const carrera_id = carreraData.id || validarData.carrera_id;
const carreraNombre = carreraData.carrera || validarData.carrera_nombre || 'Carrera ' + carrera_id;

const allRows = items.map(item => item.json);
console.log(`Total filas del Excel: ${allRows.length}`);

// ГўвЂќв‚¬ГўвЂќв‚¬ CONFIGURACION ГўвЂќв‚¬ГўвЂќв‚¬
const HEADER_KEYWORDS = {
  numero_docente: ['n Г‚В°', 'nГ‚В°', 'nro.', 'nro', 'numero', '#'],
  docente: ['docente', 'nombre docente', 'nombre del docente', 'profesor'],
  titulo_pregrado: ['pregrado'],
  titulo_posgrado: ['posgrado', 'postgrado'],
  materia: ['materia', 'asignatura', 'curso', 'nombre materia', 'nombre de la materia'],
  codigo_materia: ['codigo', 'codigo materia', 'cod'],
  ciclo: ['ciclo', 'nivel', 'semestre'],
  malla: ['malla'],
  paralelo: ['paralelo', 'grupo', 'seccion'],
  dia: ['dia de clase', 'dia clase', 'horario dia', 'dia', 'horario'],
  hora: ['hora clase', 'hora'],
  horas_teoricas: ['horas teoricas', 'teoricas', 'componente docente'],
  horas_practicas: ['horas practicas', 'practicas', 'componente practico'],
  numero_alumnos: ['nro. alumnos', 'alumnos', 'estudiantes', 'numero alumnos', 'nro alumnos', 'nro. estudiantes', 'num estudiantes', 'num alumnos', '# estudiantes', '# alumnos'],
  aula: ['aula', 'sala', 'lugar', 'aula/lab'],
  numero_horas: ['nro. horas', 'numero horas', 'nro horas'],
  total_horas: ['total horas', 'total horas clase'],
};

const SECCION_KEYWORDS = [
  'tiempo completo', 'tiempo parcial', 'docentes tiempo',
  'profesores tiempo', 'catedraticos'
];

const VALORES_NULOS = ['n/a', 'na', 'n.a', '-', '--', '---', '', 'sin dato', 'sd', 'nd'];
const MERGED_NIVEL_1 = ['numero_docente', 'docente', 'titulo_pregrado', 'titulo_posgrado'];
const MERGED_NIVEL_2 = ['materia', 'codigo_materia'];

// ГўвЂќв‚¬ГўвЂќв‚¬ FUNCION: normalizar texto para comparacion ГўвЂќв‚¬ГўвЂќв‚¬
const norm = (s) => {
  if (!s) return '';
  return String(s).toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();
};

// ГўвЂќв‚¬ГўвЂќв‚¬ FUNCION: detectar header en una fila ГўвЂќв‚¬ГўвЂќв‚¬
function detectHeader(row) {
  const entries = Object.entries(row);
  let matches = 0;
  const tempMap = {};
  for (const [key, val] of entries) {
    if (!val || typeof val !== 'string') continue;
    const clean = norm(val);
    for (const [campo, keywords] of Object.entries(HEADER_KEYWORDS)) {
      if (tempMap[campo]) continue;
      for (const kw of keywords) {
        if (clean.includes(norm(kw))) {
          tempMap[campo] = key;
          matches++;
          break;
        }
      }
    }
  }
  return { matches, tempMap };
}

// ГўвЂќв‚¬ГўвЂќв‚¬ PASO 1: Buscar el mejor bloque de header en TODAS las filas ГўвЂќв‚¬ГўвЂќв‚¬
// Con readAllSheets, las filas de multiples hojas se mezclan.
// Buscamos la fila con MAS matches de keywords de header.
let columnMap = {};
let dataStartIndex = 0;
let bestMatches = 0;

// Primero: verificar si los keys del JSON ya son headers reales
const allKeys = Object.keys(allRows[0] || {});
const hasRealHeaders = allKeys.some(k => {
  const n = norm(k);
  return !k.startsWith('__EMPTY') && !k.startsWith('__rowNum') && 
    (n.includes('docente') || n.includes('materia') || n.includes('hora') || n.includes('dia'));
});

if (hasRealHeaders) {
  for (const key of allKeys) {
    const clean = norm(key);
    for (const [campo, keywords] of Object.entries(HEADER_KEYWORDS)) {
      if (columnMap[campo]) continue;
      for (const kw of keywords) {
        if (clean.includes(norm(kw))) {
          columnMap[campo] = key;
          break;
        }
      }
    }
  }
  dataStartIndex = 0;
  bestMatches = Object.keys(columnMap).length;
} else {
  // Escanear TODAS las filas buscando el mejor header
  for (let i = 0; i < allRows.length; i++) {
    const row = allRows[i];
    const { matches, tempMap } = detectHeader(row);
    if (matches > bestMatches) {
      bestMatches = matches;
      columnMap = tempMap;
      dataStartIndex = i + 1;
    }
    // Si encontramos 6+ matches es un header excelente, pero seguimos buscando uno mejor
  }
}

console.log(`Header detectado con ${bestMatches} columnas en fila ${dataStartIndex - 1}`);
console.log('Columnas mapeadas: ' + JSON.stringify(columnMap));

// ГўвЂќв‚¬ГўвЂќв‚¬ PASO 1b: Verificar sub-headers (fila siguiente al header) ГўвЂќв‚¬ГўвЂќв‚¬
// Algunos Excels tienen 2 filas de header: fila 1 = 'HORARIO', fila 2 = 'DIA' + 'HORA'
if (dataStartIndex < allRows.length) {
  const subRow = allRows[dataStartIndex];
  const { matches: subMatches, tempMap: subMap } = detectHeader(subRow);
  // Si la sub-fila tiene campos que no teniamos, agregarlos
  for (const [campo, key] of Object.entries(subMap)) {
    if (!columnMap[campo]) {
      columnMap[campo] = key;
      console.log(`Sub-header: agregando ${campo} -> ${key}`);
    }
  }
  // Si la sub-fila tenia matches, la data empieza despues
  if (subMatches >= 2) {
    dataStartIndex++;
  }
}

// ГўвЂќв‚¬ГўвЂќв‚¬ PASO 2: Extraer registros ГўвЂќв‚¬ГўвЂќв‚¬
// Tomar filas desde dataStartIndex hasta encontrar un bloque con keys totalmente diferentes
// (indicando que empezo otra hoja del Excel)
const dataRows = allRows.slice(dataStartIndex);
const registros = [];
let seccionActual = 'TIEMPO COMPLETO';
let consecutivasVacias = 0;

for (const row of dataRows) {
  // Verificar si esta fila pertenece a otra hoja (keys diferentes)
  const rowKeys = Object.keys(row);
  const keysMatch = Object.values(columnMap).some(k => rowKeys.includes(k));
  if (!keysMatch && rowKeys.length > 0) {
    // Las keys no coinciden - probablemente cambio de hoja
    consecutivasVacias++;
    // if (consecutivasVacias > 3) break; // Disabled to support multi-sheet // Definitivamente otra hoja
    continue;
  }
  consecutivasVacias = 0;

  // Detectar si es fila de seccion
  const allValues = Object.values(row).filter(Boolean).map(v => norm(String(v))).join(' ');
  const esSeccion = SECCION_KEYWORDS.some(kw => allValues.includes(norm(kw)));
  if (esSeccion) {
    if (allValues.includes('parcial')) seccionActual = 'TIEMPO PARCIAL';
    else if (allValues.includes('completo')) seccionActual = 'TIEMPO COMPLETO';
    continue;
  }

  // Extraer campos usando columnMap
  const registro = { _seccion: seccionActual };
  let camposConValor = 0;

  for (const [campo, key] of Object.entries(columnMap)) {
    let val = row[key];
    if (val !== null && val !== undefined && String(val).trim() !== '') {
      val = String(val).trim();
      if (VALORES_NULOS.includes(val.toLowerCase())) {
        registro[campo] = null;
      } else {
        registro[campo] = val;
        camposConValor++;
      }
    } else {
      registro[campo] = null;
    }
  }

  if (camposConValor >= 2) {
    registros.push(registro);
  }
}

console.log(`Registros extraidos (pre-propagacion): ${registros.length}`);

// ГўвЂќв‚¬ГўвЂќв‚¬ PASO 3: Propagacion inteligente de celdas merged ГўвЂќв‚¬ГўвЂќв‚¬
const lastDoc = {};
const lastMat = {};

for (const reg of registros) {
  if (reg.numero_docente && String(reg.numero_docente).trim() !== '') {
    for (const campo of MERGED_NIVEL_1) {
      if (reg[campo]) lastDoc[campo] = reg[campo];
    }
    if (reg.materia) {
      for (const campo of MERGED_NIVEL_2) {
        if (reg[campo]) lastMat[campo] = reg[campo];
      }
    }
  } else if (reg.docente && String(reg.docente).trim() !== '') {
    for (const campo of MERGED_NIVEL_1) {
      if (reg[campo]) lastDoc[campo] = reg[campo];
    }
    if (reg.materia) {
      for (const campo of MERGED_NIVEL_2) {
        if (reg[campo]) lastMat[campo] = reg[campo];
      }
    }
  } else {
    for (const campo of MERGED_NIVEL_1) {
      if (!reg[campo]) reg[campo] = lastDoc[campo] || null;
    }
    if (reg.materia && String(reg.materia).trim() !== '') {
      for (const campo of MERGED_NIVEL_2) {
        if (reg[campo]) lastMat[campo] = reg[campo];
      }
    } else {
      for (const campo of MERGED_NIVEL_2) {
        if (!reg[campo]) reg[campo] = lastMat[campo] || null;
      }
    }
  }
}

// ГўвЂќв‚¬ГўвЂќв‚¬ PASO 4: Parsear horarios y formatear clases ГўвЂќв‚¬ГўвЂќв‚¬
const sanitize = (str) => {
  if (!str || str === 'null') return null;
  return String(str).replace(/\\/g, '\\\\').replace(/'/g, "''").replace(/\s+/g, ' ').trim();
};

const normalizeHora = (h) => {
  if (!h) return '';
  let s = String(h).trim();
  // Normalizar H00 -> :00 (formato 08H00)
  s = s.replace(/(\d{1,2})[Hh](\d{2})/, '$1:$2');
  // Si no tiene ':', agregar :00
  if (s && !s.includes(':') && /^\d+$/.test(s)) s += ':00';
  return s;
};

const clases = [];
for (const reg of registros) {
  if (!reg.materia && !reg.dia) continue;
  if (reg.materia && /^\d+\s*horas?$/i.test(String(reg.materia))) continue;
  if (reg.total_horas && !reg.dia && !reg.materia) continue;

  const diaRaw = String(reg.dia || '').trim();
  const horaRaw = String(reg.hora || '').trim();
  const num_est = parseInt(reg.numero_alumnos) || 0;
  const cicloVal = reg.ciclo || reg.codigo_materia || '';

  // ГўвЂќв‚¬ГўвЂќв‚¬ Manejar horarios multi-linea ГўвЂќв‚¬ГўвЂќв‚¬
  // Formato 1: dia='Lunes\r\nMartes', hora='08:00 - 10:00\r\n08:00 - 10:00'
  // Formato 2: dia='LUNES: 08H00 - 10H00\r\nMIERCOLES: 08H00 - 10H00' (dia+hora juntos)

  const diasList = diaRaw.split(/\r?\n/).map(d => d.trim()).filter(Boolean);
  const horasList = horaRaw.split(/\r?\n/).map(h => h.trim()).filter(Boolean);

  if (diasList.length === 0 && horasList.length === 0) {
    // Sin dia ni hora, pero tiene materia - agregar con datos vacios
    clases.push({
      carrera: sanitize(carreraNombre),
      materia: sanitize(reg.materia) || 'Sin nombre',
      ciclo: sanitize(String(cicloVal)),
      paralelo: sanitize(reg.paralelo) || 'A',
      dia: '',
      hora_inicio: '',
      hora_fin: '',
      num_estudiantes: num_est,
      docente: sanitize(reg.docente) || '',
      aula_sugerida: sanitize(reg.aula),
      nombre_archivo: validarData.nombre_archivo || 'n8n-upload'
    });
    continue;
  }

  // Comprobar si el dia contiene hora embebida (ej: 'LUNES: 08H00 - 10H00')
  const diaConHora = diasList.length > 0 && diasList[0].includes(':') && /\d/.test(diasList[0]);

  if (diaConHora && horasList.length === 0) {
    // Formato embebido: 'LUNES: 08H00 - 10H00'
    for (const entry of diasList) {
      const colonIdx = entry.indexOf(':');
      if (colonIdx === -1) continue;
      const dia = entry.substring(0, colonIdx).trim();
      const horaStr = entry.substring(colonIdx + 1).trim();
      let hi = '', hf = '';
      if (horaStr.includes('-')) {
        const parts = horaStr.split(/\s*-\s*/);
        hi = normalizeHora(parts[0]);
        hf = normalizeHora(parts[1]);
      }
      clases.push({
        carrera: sanitize(carreraNombre),
        materia: sanitize(reg.materia) || 'Sin nombre',
        ciclo: sanitize(String(cicloVal)),
        paralelo: sanitize(reg.paralelo) || 'A',
        dia: sanitize(dia) || '',
        hora_inicio: hi,
        hora_fin: hf,
        num_estudiantes: num_est,
        docente: sanitize(reg.docente) || '',
        aula_sugerida: sanitize(reg.aula),
        nombre_archivo: validarData.nombre_archivo || 'n8n-upload'
      });
    }
  } else {
    // Formato normal: dias y horas en columnas separadas
    const maxEntries = Math.max(diasList.length, horasList.length, 1);
    for (let i = 0; i < maxEntries; i++) {
      const diaVal = diasList[i] || diasList[diasList.length - 1] || '';
      const horaVal = horasList[i] || horasList[horasList.length - 1] || '';

      let hi = '', hf = '';
      if (horaVal.includes('-')) {
        const parts = horaVal.split(/\s*-\s*/);
        hi = normalizeHora(parts[0]);
        hf = normalizeHora(parts[1]);
      } else if (horaVal) {
        hi = normalizeHora(horaVal);
      }

      clases.push({
        carrera: sanitize(carreraNombre),
        materia: sanitize(reg.materia) || 'Sin nombre',
        ciclo: sanitize(String(cicloVal)),
        paralelo: sanitize(reg.paralelo) || 'A',
        dia: sanitize(diaVal) || '',
        hora_inicio: hi,
        hora_fin: hf,
        num_estudiantes: num_est,
        docente: sanitize(reg.docente) || '',
        aula_sugerida: sanitize(reg.aula),
        nombre_archivo: validarData.nombre_archivo || 'n8n-upload'
      });
    }
  }
}

console.log(`${clases.length} clases extraidas (pre-deduplicacion)`);

// ГўвЂќв‚¬ГўвЂќв‚¬ PASO 5: Deduplicacion inteligente ГўвЂќв‚¬ГўвЂќв‚¬
// Cuando multiples hojas tienen las mismas clases, eliminar duplicados
// Clave: materia + docente + paralelo + ciclo (normalizado)
const uniqueMap = new Map();
let dupsRemoved = 0;
for (const c of clases) {
  const key = [norm(c.materia || ''), norm(c.docente || ''), norm(c.paralelo || ''), norm(c.ciclo || '')].join('|');
  if (!uniqueMap.has(key)) {
    uniqueMap.set(key, c);
  } else {
    dupsRemoved++;
    const existing = uniqueMap.get(key);
    // Reemplazar si el nuevo tiene mas datos completos
    const scoreNew = (c.dia ? 1 : 0) + (c.hora_inicio ? 1 : 0) + (c.num_estudiantes > 0 ? 1 : 0) + (c.docente ? 1 : 0);
    const scoreOld = (existing.dia ? 1 : 0) + (existing.hora_inicio ? 1 : 0) + (existing.num_estudiantes > 0 ? 1 : 0) + (existing.docente ? 1 : 0);
    if (scoreNew > scoreOld) uniqueMap.set(key, c);
  }
}
const clasesUnicas = Array.from(uniqueMap.values());
if (dupsRemoved > 0) console.log(`Deduplicacion: ${clases.length} -> ${clasesUnicas.length} (${dupsRemoved} duplicados eliminados)`);

return {
  clases: clasesUnicas,
  carrera_id: carrera_id,
  carrera_nombre: sanitize(carreraNombre),
  total: clasesUnicas.length,
  total_filas_excel: allRows.length,
  nombre_archivo: validarData.nombre_archivo || 'n8n-upload',
  columnas_detectadas: columnMap
};

