// ALGORITMO OPTIMIZADO DE DISTRIBUCIГѓвЂњN UIDE
const EXCLUIDAS = ['AUDITORIO'];
const EXCLUSIVAS = {'SALA DE AUDIENCIAS':['DERECHO'],'AUDIENCIAS':['DERECHO'],'AULA 20':['PSICOLOGIA','PSICOLOGГѓВЌA'],'AULA20':['PSICOLOGIA','PSICOLOGГѓВЌA'],'LABORATORIO DE PSICOLOGIA':['PSICOLOGIA','PSICOLOGГѓВЌA'],'C15':['ARQUITECTURA'],'C16':['ARQUITECTURA'],'C17':['ARQUITECTURA'],'C18':['ARQUITECTURA']};
const PRIORIDAD = {'LABORATORIO 1':['INFORMATICA','INFORMГѓВЃTICA','SISTEMAS','TECNOLOGIA','TECNOLOGГѓВЌA'],'LABORATORIO 2':['INFORMATICA','INFORMГѓВЃTICA','SISTEMAS','TECNOLOGIA','TECNOLOGГѓВЌA'],'LABORATORIO 3':['INFORMATICA','INFORMГѓВЃTICA','SISTEMAS','TECNOLOGIA','TECNOLOGГѓВЌA'],'LAB1':['INFORMATICA','INFORMГѓВЃTICA','SISTEMAS','TECNOLOGIA','TECNOLOGГѓВЌA'],'LAB2':['INFORMATICA','INFORMГѓВЃTICA','SISTEMAS','TECNOLOGIA','TECNOLOGГѓВЌA'],'LAB3':['INFORMATICA','INFORMГѓВЃTICA','SISTEMAS','TECNOLOGIA','TECNOLOGГѓВЌA']};
const norm = t => t ? t.toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').trim() : '';

const clasesRaw = $('Obtener Clases Pendientes').all().map(i => i.json);
const aulasRaw = $input.all().map(i => i.json);
const clases = Array.isArray(clasesRaw[0]) ? clasesRaw[0] : clasesRaw;
const todasAulas = Array.isArray(aulasRaw[0]) ? aulasRaw[0] : aulasRaw;

// Pre-compute aula properties
const aulasInfo = todasAulas.map(a => {
  const n = norm(a.nombre), c = norm(a.codigo), t = norm(a.tipo);
  const bloqueada = EXCLUIDAS.some(b => n.includes(b) || c.includes(b) || t === b);
  let exclKey = null;
  for (const [key] of Object.entries(EXCLUSIVAS)) { if (n.includes(key) || c.includes(key)) { exclKey = key; break; } }
  let prioKey = null;
  for (const [key] of Object.entries(PRIORIDAD)) { if (n.includes(key) || c.includes(key)) { prioKey = key; break; } }
  return { ...a, _n: n, _c: c, _bloqueada: bloqueada, _exclKey: exclKey, _prioKey: prioKey };
}).filter(a => !a._bloqueada);

const aulas = aulasInfo.sort((a,b) => a.capacidad - b.capacidad);
const occ = {};
const asignaciones = [];
const noAsignadas = [];

function disp(cod, dia, ini, fin) {
  const key = cod + '|' + dia;
  if (!occ[key]) return true;
  for (let i = 0; i < occ[key].length; i++) {
    const [oi, of_] = occ[key][i];
    if (ini < of_ && fin > oi) return false;
  }
  return true;
}

function ocup(cod, dia, ini, fin) {
  const key = cod + '|' + dia;
  if (!occ[key]) occ[key] = [];
  occ[key].push([ini, fin]);
}

function buscar(clase, soloRegla) {
  const ne = clase.num_estudiantes || 1;
  const car = norm(clase.carrera);
  let mejor = null, menorDif = Infinity;
  for (const a of aulas) {
    if (a.capacidad < ne) continue;
    if (a._exclKey) {
      const ok = EXCLUSIVAS[a._exclKey].some(cr => car.includes(cr));
      if (!ok) continue;
      if (soloRegla || true) { /* exclusive match */ }
    } else if (a._prioKey) {
      const ok = PRIORIDAD[a._prioKey].some(cr => car.includes(cr));
      if (soloRegla && !ok) continue;
      if (!soloRegla && !ok) continue;
    } else {
      if (soloRegla) continue;
    }
    if (clase.dia && clase.hora_inicio && clase.hora_fin && !disp(a.codigo, clase.dia, clase.hora_inicio, clase.hora_fin)) continue;
    const d = a.capacidad - ne;
    if (d < menorDif) { menorDif = d; mejor = a; }
  }
  if (!mejor && !soloRegla) {
    menorDif = Infinity;
    for (const a of aulas) {
      if (a.capacidad < ne) continue;
      if (a._exclKey && !EXCLUSIVAS[a._exclKey].some(cr => car.includes(cr))) continue;
      if (clase.dia && clase.hora_inicio && clase.hora_fin && !disp(a.codigo, clase.dia, clase.hora_inicio, clase.hora_fin)) continue;
      const d = a.capacidad - ne;
      if (d < menorDif) { menorDif = d; mejor = a; }
    }
  }
  return mejor;
}

const rest = [];
for (const c of clases) {
  const a = buscar(c, true);
  if (a) {
    asignaciones.push({clase_id:c.clase_id,aula_id:a.id,aula_codigo:a.codigo,aula_nombre:a.nombre,capacidad_aula:a.capacidad,num_estudiantes:c.num_estudiantes,materia:c.materia,ciclo:c.ciclo,paralelo:c.paralelo,carrera:c.carrera,dia:c.dia,hora_inicio:c.hora_inicio,hora_fin:c.hora_fin,docente:c.docente});
    if (c.dia && c.hora_inicio && c.hora_fin) ocup(a.codigo, c.dia, c.hora_inicio, c.hora_fin);
  } else rest.push(c);
}
for (const c of rest) {
  const a = buscar(c, false);
  if (a) {
    asignaciones.push({clase_id:c.clase_id,aula_id:a.id,aula_codigo:a.codigo,aula_nombre:a.nombre,capacidad_aula:a.capacidad,num_estudiantes:c.num_estudiantes,materia:c.materia,ciclo:c.ciclo,paralelo:c.paralelo,carrera:c.carrera,dia:c.dia,hora_inicio:c.hora_inicio,hora_fin:c.hora_fin,docente:c.docente});
    if (c.dia && c.hora_inicio && c.hora_fin) ocup(a.codigo, c.dia, c.hora_inicio, c.hora_fin);
  } else noAsignadas.push({clase_id:c.clase_id,materia:c.materia,num_estudiantes:c.num_estudiantes,dia:c.dia,hora_inicio:c.hora_inicio,hora_fin:c.hora_fin,razon:'Sin aula disponible'});
}
const total = clases.length || 1;
return {asignaciones, clases_no_asignadas:noAsignadas, total_asignadas:asignaciones.length, total_no_asignadas:noAsignadas.length, porcentaje_exito:((asignaciones.length/total)*100).toFixed(2), timestamp:new Date().toISOString()};

